mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY CI.COMP_PAGE_DATE DESC, C.COMPANY_NUMBER DESC ) AS RN, C.COMPANY_NUMBER, C.COMPANY_NAME, F.FILE_PATH, C.COMPANY_ADDRESS, CI.COMP_TYPE, CI.COMP_SUMMARY, TO_CHAR(CI.COMP_PAGE_DATE, 'YYYY-MM-DD') AS COMP_PAGE_DATE, NVL(JP.CAT1_IS_HIRING, 0) AS CAT1_IS_HIRING, NVL(JP.CAT2_IS_HIRING, 0) AS CAT2_IS_HIRING, NVL(JP.CAT3_IS_HIRING, 0) AS CAT3_IS_HIRING, NVL(JP.CAT4_IS_HIRING, 0) AS CAT4_IS_HIRING FROM TBL_COMPANY C JOIN TBL_COMP_INFO CI ON C.COMPANY_NUMBER = CI.COMPANY_NUMBER LEFT JOIN TBL_FILE F ON C.COMPANY_NUMBER = F.COMPANY_NUMBER LEFT JOIN TBL_JOB_POST JP ON C.COMPANY_NUMBER = JP.COMPANY_NUMBER WHERE C.COMPANY_STATE = '승인'
AND NVL(JP.CAT1_IS_HIRING, 0) = 1
AND NVL(JP.CAT2_IS_HIRING, 0) = 1
AND NVL(JP.CAT3_IS_HIRING, 0) = 1
AND NVL(JP.CAT4_IS_HIRING, 0) = 1
) WHERE RN BETWEEN #{startRow} AND #{endRow}
